body.script:
const params = new URLSearchParams(window.location.search);
params.set("t", Date.now());
const safeUrl = "https://cdn.jsdelivr.net/gh/MRVAPORWAVE25/DuckMath@main/duck.html" + "?" + params.toString();
let l = `
\x3Cscript>
launch();
function launch() {
  try {
    const url = decodeURIComponent("${safeUrl}");
    fetch(url).then(response => response.text())
      .then(html => {
        document.open();
        document.write(html);
        document.close();
      });
  } catch (error) {
    console.error('error:', error);
  }
}
\x3C/script>`; 
var theIframe = document.getElementById('test'); 
theIframe.srcdoc = l;
